#!/usr/bin/env python3
"""Regenerate Features.g.cs for each RuntimeApps bench fixture assembly.

Run from the repository root:
    python3 tools/gen-bench-features.py
"""
from __future__ import annotations

from pathlib import Path

SIZES = [50, 100, 200]

# POST_COUNT = N // 10; GET_COUNT = N - POST_COUNT
# e.g. N=50  → GET f0..f44 (45), POST f0..f4 (5)
#      N=100 → GET f0..f89 (90), POST f0..f9 (10)
#      N=200 → GET f0..f179 (180), POST f0..f19 (20)

_HEADER = """\
// <auto-generated/>
// SliceFx runtime benchmark feature fixtures.
// Regenerate: python3 tools/gen-bench-features.py

#pragma warning disable CS1591
#pragma warning disable CA1707
#nullable enable

namespace SliceFx.Bench{n}.Features;

using System.ComponentModel.DataAnnotations;
using SliceFx;

"""

_GET_BLOCK = """\
[Feature("GET /bench/s/f{i}")]
public static class SimpleGetFeature{i}
{{
    public record Response(int Index);
    public static Response Handle() => new({i});
}}"""

_POST_BLOCK = """\
[Feature("POST /bench/v/f{i}")]
public static class PostValidFeature{i}
{{
    public record Request([Required, MinLength(2)] string Name, [Required, EmailAddress] string Email);
    public record Response(string Name);
    public static Response Handle(Request req) => new(req.Name);
}}"""


def _generate(n: int) -> str:
    post_count = n // 10
    get_count = n - post_count
    blocks = [_GET_BLOCK.format(i=i) for i in range(get_count)]
    blocks += [_POST_BLOCK.format(i=i) for i in range(post_count)]
    return _HEADER.format(n=n) + "\n\n".join(blocks) + "\n"


def main() -> None:
    repo_root = Path(__file__).parent.parent
    for n in SIZES:
        out = repo_root / f"tests/SliceFx.Benchmarks.RuntimeApps/Bench{n}/Features.g.cs"
        out.write_text(_generate(n), encoding="utf-8")
        print(f"Wrote {out.relative_to(repo_root)}")


if __name__ == "__main__":
    main()
